/**
 * Creative North Star: "The Prestigious Curator"
 *
 * The system is designed to feel like a premium academic journal—
 * authoritative yet breathable. We achieve this through "Institutional Innovation":
 * combining the gravitas of HCM-UTE's heritage with a forward-thinking digital execution.
 *
 * Key Principles:
 * 1. No-Line Rule: No 1px solid borders. Structure via tonal transitions.
 * 2. Layered Surface: UI as stacked academic papers on a desk.
 * 3. Glass & Gradient: Glassmorphism for floating elements, gradients for CTAs.
 * 4. Editorial Typography: Be Vietnam Pro for Vietnamese, Inter for body.
 * 5. Excellence Accents: Gold/Emerald as rare "rewards" for the eye.
 */
import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "inline-flex items-center justify-center whitespace-nowrap rounded-lg text-sm font-medium transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 active:scale-[0.98]",
  {
    variants: {
      variant: {
        default: "bg-primary text-white hover:bg-primary/90 shadow-glow-primary",
        destructive:
          "bg-error text-white hover:bg-error/90",
        outline:
          "border border-outline-variant bg-surface-container-lowest text-on-surface hover:bg-surface-container-high",
        secondary:
          "bg-secondary-container text-primary hover:bg-secondary-container/80",
        ghost: "hover:bg-surface-container-high hover:text-primary",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-10 px-5 py-2.5",
        sm: "h-9 rounded-md px-3 text-xs",
        lg: "h-11 rounded-md px-8 text-base",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button"
    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        {...props}
      />
    )
  }
)
Button.displayName = "Button"

export { Button, buttonVariants }
